const allData = $input.all();

// If no SF match was found upstream, skip this iteration cleanly
if (allData.find(i => i.json._no_match)) {
    return [{
        json: {
            context: {
                meeting_type: "Unknown",
                meeting_title: "No account match found",
                account_name: "Unknown Account",
                analytics: {},
                _skip: true
            }
        }
    }];
}

// --- 1. Salesforce Account Data ---
const sfItem = allData.find(i => i.json.Id && i.json.Name) || {};
const sfData = sfItem.json || {};

// --- 2. Emails ---
let emails = allData.find(i => i.json.Emails)?.json.Emails || [];
if (emails.length === 1 && emails[0].notice) emails = 'No email data found for this account.';

// --- 3. Feature & Add-On Recommendations ---
let recommendations = allData.find(i => i.json['Feature & Add On'])?.json['Feature & Add On'] || [];
recommendations = Array.isArray(recommendations) ? recommendations.filter(rec => Object.keys(rec).length > 0) : [];
if (recommendations.length === 0) recommendations = 'No add-on or feature recommendations found.';

// --- 4. Zendesk Tickets ---
let tickets = allData.find(i => i.json['Zendesk Tickets'])?.json['Zendesk Tickets'] || [];
if (tickets.length === 1 && tickets[0].notice) tickets = 'No Zendesk tickets found for this account.';

// --- 5. Call Transcripts ---
let transcripts = allData.find(i => i.json['Call Transcripts'])?.json['Call Transcripts'] || [];
if (transcripts.length === 1 && transcripts[0].notice) transcripts = 'No Modjo call transcripts found for this account.';

// --- 6. Product Adoption - take first row only ---
let productAdoption = allData.find(i => i.json['Product Adoption'])?.json['Product Adoption'] || [];
productAdoption = Array.isArray(productAdoption) && productAdoption.length > 0 ? productAdoption[0] : null;
if (!productAdoption) productAdoption = 'No product adoption data found.';

// --- 7. All Opportunities - split into 3 buckets ---
const allOpps = allData.find(i => i.json['All Opportunities'])?.json['All Opportunities'] || [];

// --- 8. Account Summary ---
let accountSummary = allData.find(i => i.json['Account Summary'])?.json['Account Summary'] || [];
accountSummary = Array.isArray(accountSummary) && accountSummary.length > 0 ? accountSummary[0] : null;
if (!accountSummary) accountSummary = 'No account summary available.';

const closedLostAddons = allOpps
  .filter(o => o.StageName === 'Closed Lost' && o.Plan_Change_Source__c === 'Add-On Center')
  .map(o => ({
    name: o.Name,
    close_date: o.CloseDate,
    lost_reason: o.Lost_Reason__c || 'N/A'
  }));

const activeAddons = allOpps
  .filter(o => o.StageName === 'Closed Won' && o.Plan_Change_Source__c === 'Add-On Center')
  .map(o => ({
    name: o.Name,
    close_date: o.CloseDate,
    amount: o.Amount || null
  }));

const onboardingOpp = allOpps.find(o =>
  o.IsWon === true && o.Plan_Change_Source__c !== 'Add-On Center'
) || null;

const onboardingData = onboardingOpp ? {
  name: onboardingOpp.Name,
  close_date: onboardingOpp.CloseDate,
  modjo_ho_summary: onboardingOpp.Modjo_HO_Summary__c || null,
  mmf_start_date: onboardingOpp.MMF_Start_Date_60__c || null,
  mmf_amount: onboardingOpp.Converted_MMF_MAF_Amount__c || null,
  pricing_model: onboardingOpp.Pricing_Model_Type_F__c || null,
  opt_out_days: onboardingOpp.Opt_Out_Period_Days__c || null,
  contract_term: onboardingOpp.Contract_Term__c || null
} : null;

// --- 9. Meeting Metadata ---
// FIX: removed underscore prefix from all 4 field references (was _meeting_type, _poc_email, _meeting_title, _csm_email)
const meetingData = {
  meeting_type:  sfData.meeting_type  || null,
  poc_email:     sfData.poc_email     || null,
  title:         sfData.meeting_title || null,
  csm_email:     sfData.csm_email     || null
};
const displayEmails = meetingData.poc_email
  ? meetingData.poc_email.replace(/'/g, '').replace(/,/g, ', ')
  : 'N/A';

return [{
  json: {
    context: {
      meeting_type:        meetingData.meeting_type || 'Sync',
      meeting_title:       meetingData.title || meetingData.Meeting_Name || 'Meeting with ' + (sfData.Name || 'Client'),
      poc_email:           displayEmails,
      account_name:        sfData.Name || 'Unknown Account',
      analytics: {
        Id:                                  sfData.Id,
        Guesty_Admin_ID__c:                  sfData.Guesty_Admin_ID__c,
        Main_Contact_Email__c:               sfData.Main_Contact_Email__c,
        Account_Owner_Sentiment__c:          sfData.Account_Owner_Sentiment__c,
        Months_in_Service__c:                sfData.Months_in_Service__c,
        Number_of_Active_Listed_Listings__c: sfData.Number_of_Active_Listed_Listings__c,
        Average_MRR__c:                      sfData.Average_MRR__c,
        MTD_Revenue__c:                      sfData.MTD_Revenue__c,
        Last_Month_Revenue__c:               sfData.Last_Month_Revenue__c,
        Last_Call_Date__c:                   sfData.Last_Call_Date__c,
        Onboarding_Status__c:                sfData.Onboarding_Status__c,
        Recent_Health_Score__c:              sfData.Recent_Health_Score__c,
        Last_EBR_Date__c:                    sfData.Last_EBR_Date__c,
        Next_Renewal_Date__c:                sfData.Next_Renewal_Date__c,
        Upcoming_EBR_Date__c:                sfData.Upcoming_EBR_Date__c
      },
      email_history:       emails,
      zendesk_history:     tickets,
      call_transcripts:    transcripts,
      account_summary:     accountSummary,
      recommendations:     recommendations,
      product_adoption:    productAdoption,
      closed_lost_addons:  closedLostAddons.length > 0 ? closedLostAddons : 'No previously rejected add-ons found.',
      active_addons:       activeAddons.length > 0 ? activeAddons : 'No active add-ons found.',
      onboarding_data:     onboardingData || 'No onboarding opportunity data found.'
    }
  }
}];
